            $sorted = @($g.Group | Sort-Object -Property CreatedAt -Descending)
            for ($i = $KeepLatestPerWorkflow; $i -lt $sorted.Count; $i++) {
                if ('count' -notin $sorted[$i].Reasons) { [void]$sorted[$i].Reasons.Add('count') }
            }
