            KeptCount            = $keep.Count
            DeletedCount         = $delete.Count
            TotalReclaimedBytes  = [long]$reclaimed
            DryRun               = [bool]$DryRun
            Now                  = $Now
            Policies             = [pscustomobject]@{
                MaxAgeDays            = $MaxAgeDays
                MaxTotalSizeBytes     = $MaxTotalSizeBytes
